const ASSIGN_KEY = 'lms-assignments';

let currentAttachments = [];

function handleAssignmentFileDrop(e) {
    e.preventDefault();
    const zone = document.getElementById('assignment-upload-zone');
    if (zone) zone.style.borderColor = 'var(--border)';
    if (e.dataTransfer.files) {
        processUploadedFiles(e.dataTransfer.files);
    }
}

function handleAssignmentFileSelect(e) {
    if (e.target.files) {
        processUploadedFiles(e.target.files);
    }
}

function processUploadedFiles(files) {
    for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const attachmentId = 'att_' + Math.random().toString(36).slice(2, 9);
        const item = {
            id: attachmentId,
            name: file.name,
            size: file.size,
            type: file.type || getFallbackMimeType(file.name)
        };

        // Read content as Base64 if file is small (< 200KB)
        if (file.size < 200 * 1024) {
            const reader = new FileReader();
            reader.onload = function(event) {
                item.data = event.target.result;
                currentAttachments.push(item);
                renderModalAttachments();
            };
            reader.readAsDataURL(file);
        } else {
            currentAttachments.push(item);
            renderModalAttachments();
        }
    }
    // Reset input value so same file can be chosen again
    const input = document.getElementById('assignment-file-input');
    if (input) input.value = '';
}

function getFallbackMimeType(filename) {
    const ext = filename.split('.').pop().toLowerCase();
    if (ext === 'pdf') return 'application/pdf';
    if (ext === 'doc' || ext === 'docx') return 'application/msword';
    if (ext === 'xls' || ext === 'xlsx') return 'application/vnd.ms-excel';
    if (ext === 'ppt' || ext === 'pptx') return 'application/vnd.ms-powerpoint';
    if (['png', 'jpg', 'jpeg', 'gif', 'svg'].includes(ext)) return 'image/' + (ext === 'jpg' ? 'jpeg' : ext);
    return 'application/octet-stream';
}

function getFileIcon(type, filename) {
    const ext = filename.split('.').pop().toLowerCase();
    if (type.includes('pdf') || ext === 'pdf') return 'fa-solid fa-file-pdf" style="color:#ef4444;"';
    if (type.includes('word') || ext === 'doc' || ext === 'docx') return 'fa-solid fa-file-word" style="color:#3b82f6;"';
    if (type.includes('excel') || type.includes('spreadsheet') || ext === 'xls' || ext === 'xlsx') return 'fa-solid fa-file-excel" style="color:#22c55e;"';
    if (type.includes('powerpoint') || type.includes('presentation') || ext === 'ppt' || ext === 'pptx') return 'fa-solid fa-file-powerpoint" style="color:#f97316;"';
    if (type.includes('image') || ['png', 'jpg', 'jpeg', 'gif', 'svg'].includes(ext)) return 'fa-solid fa-file-image" style="color:#06b6d4;"';
    return 'fa-solid fa-file" style="color:#64748b;"';
}

function formatBytes(bytes, decimals = 2) {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

function renderModalAttachments() {
    const container = document.getElementById('assignment-files-list');
    if (!container) return;
    let html = '';
    currentAttachments.forEach((file) => {
        const icon = getFileIcon(file.type, file.name);
        html += `
            <div style="display: flex; align-items: center; justify-content: space-between; background: var(--secondary); padding: 8px 12px; border-radius: 8px; border: 1px solid var(--border); font-size: 0.85rem;">
                <div style="display: flex; align-items: center; gap: 8px; min-width: 0; flex: 1;">
                    <i class="${icon}"></i>
                    <span style="color: var(--text-main); font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-right: 6px;" title="${file.name}">${file.name}</span>
                    <span style="color: var(--text-muted); font-size: 0.75rem; flex-shrink: 0;">(${formatBytes(file.size)})</span>
                </div>
                <button type="button" onclick="removeAttachment('${file.id}')" style="background: none; border: none; color: var(--danger-text); cursor: pointer; padding: 4px; display: flex; align-items: center; justify-content: center; transition: opacity 0.2s;" onmouseover="this.style.opacity=0.7" onmouseout="this.style.opacity=1">
                    <i class="fa-solid fa-trash-can"></i>
                </button>
            </div>
        `;
    });
    container.innerHTML = html;
}

function removeAttachment(id) {
    currentAttachments = currentAttachments.filter(f => f.id !== id);
    renderModalAttachments();
}

function downloadAttachmentFile(assignmentId, attachmentId) {
    const assignments = getAssignments();
    const assignment = assignments.find(a => a.id === assignmentId);
    if (!assignment || !assignment.attachments) return;
    const file = assignment.attachments.find(f => f.id === attachmentId);
    if (!file) return;

    let downloadUrl = file.data;
    if (!downloadUrl) {
        // Generate a mock text file if data is not stored
        const content = `เอกสารประกอบการเรียน\n\nหัวข้อ: ${assignment.title}\nไฟล์แนบ: ${file.name}\nขนาด: ${formatBytes(file.size)}\n\nคำชี้แจง: นี่คือไฟล์เอกสารแนบต้นแบบสำหรับชั้นเรียนวิทยาการคำนวณ`;
        const blob = new Blob([content], { type: file.type || 'text/plain' });
        downloadUrl = URL.createObjectURL(blob);
    }

    const a = document.createElement('a');
    a.href = downloadUrl;
    a.download = file.name;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    if (!file.data) {
        URL.revokeObjectURL(downloadUrl);
    }
}
